import React, { useEffect, useState } from "react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import {
  Brain,
  RefreshCw,
  CheckCircle2,
  TrendingUp,
  Zap,
  Network,
  Layers,
  Activity,
} from "lucide-react";

const MODEL_ICONS = {
  logistic_regression: Brain,
  random_forest: Layers,
  xgboost: TrendingUp,
  lightgbm: Zap,
  mlp: Network,
};

const ModelSelector = ({ apiUrl, onModelChange }) => {
  const [models, setModels] = useState([]);
  const [currentModel, setCurrentModel] = useState(null);
  const [loading, setLoading] = useState(false);
  const [switching, setSwitching] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchModels();
  }, []);

  const fetchModels = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(`${apiUrl}/models`);
      const data = await response.json();

      if (data.success) {
        setModels(data.models);
        setCurrentModel(data.current_model);
      } else {
        setError(data.error || "Failed to fetch models");
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const switchModel = async (modelId) => {
    setSwitching(modelId);
    setError(null);

    try {
      const response = await fetch(`${apiUrl}/models/${modelId}`, {
        method: "POST",
      });

      const data = await response.json();

      if (data.success) {
        setCurrentModel(modelId);
        
        // Notify parent component
        if (onModelChange) {
          onModelChange(modelId, data.model_name);
        }
      } else {
        setError(data.error || "Failed to switch model");
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setSwitching(null);
    }
  };

  const formatPerformance = (perf) => {
    if (!perf) return null;
    return {
      accuracy: (perf.accuracy * 100).toFixed(1),
      precision: (perf.precision * 100).toFixed(1),
      recall: (perf.recall * 100).toFixed(1),
      f1: (perf.f1_score * 100).toFixed(1),
      rocAuc: (perf.roc_auc * 100).toFixed(1),
    };
  };

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Activity className="h-5 w-5 animate-pulse" />
            Loading Models...
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-gray-500">Fetching available models...</p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Brain className="h-5 w-5 text-blue-600" />
                Model Selection
              </CardTitle>
              <CardDescription>
                Choose from {models.length} trained ML models
              </CardDescription>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={fetchModels}
              disabled={loading}
            >
              <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {error && (
            <Alert variant="destructive" className="mb-4">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {models.map((model) => {
              const Icon = MODEL_ICONS[model.id] || Brain;
              const perf = formatPerformance(model.performance);
              const isActive = model.id === currentModel;
              const isSwitching = switching === model.id;

              return (
                <Card
                  key={model.id}
                  className={`cursor-pointer transition-all ${
                    isActive
                      ? "ring-2 ring-blue-500 bg-blue-50"
                      : "hover:shadow-lg"
                  } ${!model.loaded ? "opacity-50" : ""}`}
                  onClick={() => model.loaded && !isSwitching && switchModel(model.id)}
                >
                  <CardHeader className="pb-3">
                    <div className="flex items-start justify-between">
                      <div className="flex items-center gap-2">
                        <Icon className={`h-5 w-5 ${isActive ? "text-blue-600" : "text-gray-600"}`} />
                        <div>
                          <CardTitle className="text-base">
                            {model.name}
                          </CardTitle>
                        </div>
                      </div>
                      {isActive && (
                        <Badge variant="default" className="flex items-center gap-1">
                          <CheckCircle2 className="h-3 w-3" />
                          Active
                        </Badge>
                      )}
                      {!model.loaded && (
                        <Badge variant="destructive">Not Loaded</Badge>
                      )}
                    </div>
                  </CardHeader>
                  <CardContent>
                    <p className="text-xs text-gray-600 mb-3">
                      {model.description}
                    </p>

                    {perf && (
                      <div className="space-y-1">
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-600">Accuracy:</span>
                          <span className="font-semibold">{perf.accuracy}%</span>
                        </div>
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-600">Precision:</span>
                          <span className="font-semibold">{perf.precision}%</span>
                        </div>
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-600">Recall:</span>
                          <span className="font-semibold">{perf.recall}%</span>
                        </div>
                        <div className="flex justify-between text-xs">
                          <span className="text-gray-600">ROC-AUC:</span>
                          <span className="font-semibold">{perf.rocAuc}%</span>
                        </div>
                      </div>
                    )}

                    {model.loaded && !isActive && (
                      <Button
                        className="w-full mt-3"
                        variant="outline"
                        size="sm"
                        disabled={isSwitching}
                      >
                        {isSwitching ? (
                          <>
                            <RefreshCw className="h-3 w-3 mr-2 animate-spin" />
                            Switching...
                          </>
                        ) : (
                          "Switch to this model"
                        )}
                      </Button>
                    )}
                  </CardContent>
                </Card>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default ModelSelector;

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva } from "class-variance-authority";

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center justify-center rounded-full border px-2 py-0.5 text-xs font-medium w-fit whitespace-nowrap shrink-0 [&>svg]:size-3 gap-1 [&>svg]:pointer-events-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive transition-[color,box-shadow] overflow-hidden",
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground [a&]:hover:bg-primary/90",
        secondary:
          "border-transparent bg-secondary text-secondary-foreground [a&]:hover:bg-secondary/90",
        destructive:
          "border-transparent bg-destructive text-white [a&]:hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "text-foreground [a&]:hover:bg-accent [a&]:hover:text-accent-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

function Badge({
  className,
  variant,
  asChild = false,
  ...props
}) {
  const Comp = asChild ? Slot : "span"

  return (
    <Comp
      data-slot="badge"
      className={cn(badgeVariants({ variant }), className)}
      {...props} />
  );
}

export { Badge, badgeVariants }

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva } from "class-variance-authority";

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        sm: "h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}) {
  const Comp = asChild ? Slot : "button"

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props} />
  );
}

export { Button, buttonVariants }
